#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M, X, K;
        scanf("%d %d %d %d", &N, &M, &X, &K);
        char S[K + 1];
        scanf("%s", S);
        int even = 0, odd = 0;
        for (int i = 0; i < K; i++) {
            if (S[i] == 'E') even++;
            else odd++;
        }
        int patents = 0;
        for (int i = 1; i <= M; i++) {
            int workers = (i % 2 == 0) ? even : odd;
            workers = (workers < X) ? workers : X;
            patents += workers;
            if (patents >= N) break;
        }
        if (patents >= N) printf("yes\n");
        else printf("no\n");
    }
    return 0;
}

