import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int X = sc.nextInt();
            int K = sc.nextInt();
            String S = sc.next();
            int even = 0, odd = 0;
            for (int i = 0; i < K; i++) {
                if (S.charAt(i) == 'E') even++;
                else odd++;
            }
            int patents = 0;
            for (int i = 1; i <= M; i++) {
                int workers = (i % 2 == 0) ? even : odd;
                workers = (workers < X) ? workers : X;
                patents += workers;
                if (patents >= N) break;
            }
            if (patents >= N) System.out.println("yes");
            else System.out.println("no");
        }
    }
}

